/*eslint-disable*/
import React, { useState } from "react";
import { Link, useHistory } from "react-router-dom";

export default function AdminNavbar({ employeeInfo, onUpdateProfile, onLogout }) {
  const [navbarOpen, setNavbarOpen] = useState(false);
  const [sidebarOpen, setSidebarOpen] = useState(false);
  const [showJobOfferModal, setShowJobOfferModal] = useState(false);
  const [selectedJobOffer, setSelectedJobOffer] = useState(null);
  const [showResignConfirm, setShowResignConfirm] = useState(false);
  const [showLogoutConfirm, setShowLogoutConfirm] = useState(false);
  const history = useHistory();

  // Paramètres du profil
  const [tempProfile, setTempProfile] = useState({
    name: employeeInfo?.name || "Jenna Stones",
    location: employeeInfo?.location || "Paris, France",
    phone: employeeInfo?.phone || "+33 6 12 34 56 78",
    bio: employeeInfo?.bio || "Serveuse professionnelle avec 5 ans d'expérience...",
    coverImage: employeeInfo?.coverImage || "https://images.unsplash.com/photo-1517248135467-4c7edcad34c4",
    profileImage: employeeInfo?.profileImage || "https://randomuser.me/api/portraits/women/68.jpg"
  });

  // Liens sociaux
  const [socialLinks, setSocialLinks] = useState({
    facebook: "", instagram: "", twitter: "", linkedin: "", tiktok: ""
  });

  // Offres d'emploi
  const [jobOffers, setJobOffers] = useState([
    {
      id: 1,
      restaurantName: "Restaurant Andalous",
      location: "Alger, Algérie",
      description: "Nous recherchons un serveur expérimenté pour rejoindre notre équipe",
      logo: "https://cdn-icons-png.flaticon.com/512/1046/1046784.png",
      image: "https://images.unsplash.com/photo-1517248135467-4c7edcad34c4",
      phone: "+213 5 55 55 55 55",
      email: "info@andalus-restaurant.dz",
      status: "pending"
    },
    {
      id: 2,
      restaurantName: "Café Parisien",
      location: "Paris, France",
      description: "Barman recherché pour notre nouveau café",
      logo: "https://cdn-icons-png.flaticon.com/512/1046/1046784.png",
      image: "https://images.unsplash.com/photo-1501339847302-ac426a4a7cbb",
      phone: "+33 6 12 34 56 78",
      email: "contact@cafeparisien.fr",
      status: "pending"
    }
  ]);

  const [currentJob, setCurrentJob] = useState(null);

  // Fonctions
  const acceptJobOffer = (offer) => {
    setJobOffers([]);
    setCurrentJob(offer);
    setShowJobOfferModal(false);
    alert(`✅ Vous avez accepté l'offre de ${offer.restaurantName}!`);
  };

  const rejectJobOffer = (offer) => {
    setJobOffers(jobOffers.filter(job => job.id !== offer.id));
    setShowJobOfferModal(false);
    alert(`❌ Vous avez refusé l'offre de ${offer.restaurantName}`);
  };

  const resignFromJob = () => {
    setShowResignConfirm(false);
    setCurrentJob(null);
    setJobOffers([
      {
        id: 1,
        restaurantName: "Restaurant Andalous",
        location: "Alger, Algérie",
        description: "Nous recherchons un serveur expérimenté...",
        logo: "https://cdn-icons-png.flaticon.com/512/1046/1046784.png",
        image: "https://images.unsplash.com/photo-1517248135467-4c7edcad34c4",
        phone: "+213 5 55 55 55 55",
        email: "info@andalus-restaurant.dz",
        status: "pending"
      },
      {
        id: 2,
        restaurantName: "Café Parisien",
        location: "Paris, France",
        description: "Barman recherché pour notre nouveau café",
        logo: "https://cdn-icons-png.flaticon.com/512/1046/1046784.png",
        image: "https://images.unsplash.com/photo-1501339847302-ac426a4a7cbb",
        phone: "+33 6 12 34 56 78",
        email: "contact@cafeparisien.fr",
        status: "pending"
      }
    ]);
    alert("📝 Vous avez démissionné avec succès");
  };

  const handleLogout = () => {
    setShowLogoutConfirm(false);
    if (onLogout) onLogout();
    else history.push("/");
    alert("👋 Vous êtes déconnecté");
  };

  const saveProfileSettings = () => {
    if (onUpdateProfile) onUpdateProfile(tempProfile);
    alert("✅ Profil mis à jour avec succès!");
    setSidebarOpen(false);
  };

  const updateSocialLink = (platform, url) => {
    setSocialLinks({ ...socialLinks, [platform]: url });
  };

  const saveSocialLinks = () => {
    alert("✅ Liens sociaux mis à jour!");
    setSidebarOpen(false);
  };

  const SocialIcons = () => (
    <div className="flex justify-center gap-4 mt-4">
      {socialLinks.facebook && <a href={socialLinks.facebook} target="_blank" rel="noopener noreferrer" className="text-blue-500 hover:text-blue-400 transition-all duration-300 transform hover:scale-110"><i className="fab fa-facebook-f text-xl"></i></a>}
      {socialLinks.instagram && <a href={socialLinks.instagram} target="_blank" rel="noopener noreferrer" className="text-pink-500 hover:text-pink-400 transition-all duration-300 transform hover:scale-110"><i className="fab fa-instagram text-xl"></i></a>}
      {socialLinks.twitter && <a href={socialLinks.twitter} target="_blank" rel="noopener noreferrer" className="text-blue-400 hover:text-blue-300 transition-all duration-300 transform hover:scale-110"><i className="fab fa-twitter text-xl"></i></a>}
      {socialLinks.linkedin && <a href={socialLinks.linkedin} target="_blank" rel="noopener noreferrer" className="text-blue-700 hover:text-blue-600 transition-all duration-300 transform hover:scale-110"><i className="fab fa-linkedin-in text-xl"></i></a>}
      {socialLinks.tiktok && <a href={socialLinks.tiktok} target="_blank" rel="noopener noreferrer" className="text-white hover:text-gray-300 transition-all duration-300 transform hover:scale-110"><i className="fab fa-tiktok text-xl"></i></a>}
    </div>
  );

  return (
    <>
      <style>
        {`
          /* Reset */
          * {
            margin: 0;
            padding: 0;
            box-sizing: border-box;
          }
          
          /* Navbar Styles */
          .navbar-custom {
            background: linear-gradient(135deg, #9b2dff, #7c3aed, #a855f7);
            box-shadow: 0 4px 20px rgba(139, 92, 246, 0.3);
            position: fixed;
            top: 0;
            left: 0;
            right: 0;
            z-index: 1000;
          }
          
          .navbar-custom .nav-link {
            transition: all 0.3s ease;
            position: relative;
          }
          
          .navbar-custom .nav-link::after {
            content: '';
            position: absolute;
            bottom: 0;
            left: 50%;
            width: 0;
            height: 2px;
            background: #e9d5ff;
            transition: all 0.3s ease;
            transform: translateX(-50%);
          }
          
          .navbar-custom .nav-link:hover::after {
            width: 80%;
          }
          
          .navbar-custom .nav-link:hover {
            color: #e9d5ff !important;
            transform: translateY(-2px);
          }
          
          /* Settings icon button */
          .settings-icon-btn {
            background: rgba(255,255,255,0.15);
            border: 1px solid rgba(255,255,255,0.4);
            border-radius: 12px;
            width: 42px;
            height: 42px;
            display: flex;
            align-items: center;
            justify-content: center;
            cursor: pointer;
            transition: all 0.3s ease;
            margin-right: 15px;
          }
          
          .settings-icon-btn:hover {
            background: rgba(255,255,255,0.3);
            transform: scale(1.05) rotate(15deg);
            box-shadow: 0 0 15px rgba(255,255,255,0.3);
          }
          
          /* Logo text */
          .logo-text {
            background: linear-gradient(135deg, #fff, #e9d5ff);
            -webkit-background-clip: text;
            background-clip: text;
            color: transparent;
            font-weight: bold;
            letter-spacing: 2px;
          }
          
          /* Mobile menu button */
          .mobile-menu-btn {
            background: rgba(255,255,255,0.15);
            border: 1px solid rgba(255,255,255,0.4);
            border-radius: 12px;
            width: 42px;
            height: 42px;
            display: flex;
            align-items: center;
            justify-content: center;
            cursor: pointer;
            transition: all 0.3s ease;
          }
          
          .mobile-menu-btn:hover {
            background: rgba(255,255,255,0.3);
            transform: scale(1.05);
          }
          
          /* Sidebar styles */
          @keyframes slideIn {
            from { transform: translateX(-100%); }
            to { transform: translateX(0); }
          }
          
          @keyframes fadeIn {
            from { opacity: 0; }
            to { opacity: 1; }
          }
          
          .sidebar-overlay {
            position: fixed;
            top: 0;
            left: 0;
            right: 0;
            bottom: 0;
            background: rgba(0,0,0,0.6);
            backdrop-filter: blur(5px);
            z-index: 1001;
            animation: fadeIn 0.3s ease;
          }
          
          .sidebar {
            position: fixed;
            top: 0;
            left: 0;
            width: 85%;
            max-width: 380px;
            height: 100vh;
            background: linear-gradient(135deg, #9b2dff, #7c3aed, #a855f7);
            z-index: 1002;
            padding: 25px 20px;
            overflow-y: auto;
            animation: slideIn 0.3s cubic-bezier(0.4, 0, 0.2, 1);
            border-right: 2px solid rgba(168, 85, 247, 0.5);
            box-shadow: 5px 0 30px rgba(0,0,0,0.3);
          }
          
          .sidebar::-webkit-scrollbar {
            width: 5px;
          }
          
          .sidebar::-webkit-scrollbar-track {
            background: rgba(255,255,255,0.1);
            border-radius: 10px;
          }
          
          .sidebar::-webkit-scrollbar-thumb {
            background: #e9d5ff;
            border-radius: 10px;
          }
          
          .sidebar-section {
            margin-bottom: 25px;
            padding-bottom: 20px;
            border-bottom: 1px solid rgba(255,255,255,0.15);
          }
          
          .sidebar-title {
            color: #e9d5ff;
            font-size: 1rem;
            font-weight: bold;
            margin-bottom: 15px;
            display: flex;
            align-items: center;
            gap: 10px;
          }
          
          .sidebar-input {
            width: 100%;
            padding: 10px 12px;
            background: rgba(255,255,255,0.12);
            border: 1px solid rgba(255,255,255,0.25);
            border-radius: 12px;
            color: white;
            margin-bottom: 12px;
            font-size: 0.85rem;
            transition: all 0.2s;
          }
          
          .sidebar-input:focus {
            outline: none;
            border-color: #e9d5ff;
            background: rgba(255,255,255,0.2);
          }
          
          .sidebar-input::placeholder {
            color: rgba(255,255,255,0.5);
          }
          
          .sidebar-label {
            color: rgba(255,255,255,0.8);
            font-size: 0.75rem;
            margin-bottom: 5px;
            display: block;
          }
          
          .btn-sidebar {
            background: linear-gradient(135deg, rgba(107, 33, 165, 0.8), rgba(88, 28, 135, 0.8));
            border: 1px solid rgba(168, 85, 247, 0.5);
            padding: 10px;
            border-radius: 12px;
            color: white;
            font-weight: bold;
            cursor: pointer;
            width: 100%;
            margin-top: 10px;
            transition: all 0.2s;
          }
          
          .btn-sidebar:hover {
            background: linear-gradient(135deg, #7e22ce, #6b21a5);
            transform: scale(1.02);
            border-color: #e9d5ff;
          }
          
          .btn-danger-sidebar {
            background: linear-gradient(135deg, #ef4444, #b91c1c);
            border-color: #ef4444;
          }
          
          .btn-danger-sidebar:hover {
            background: linear-gradient(135deg, #dc2626, #991b1b);
          }
          
          .current-job-card {
            background: rgba(107, 33, 165, 0.3);
            border: 1px solid #a855f7;
            border-radius: 12px;
            padding: 12px;
            margin-bottom: 15px;
          }
          
          .job-offer-card {
            background: rgba(255,255,255,0.08);
            border-radius: 12px;
            padding: 12px;
            margin-bottom: 10px;
            cursor: pointer;
            transition: all 0.2s;
          }
          
          .job-offer-card:hover {
            background: rgba(255,255,255,0.15);
            transform: translateX(5px);
          }
          
          /* Modal styles */
          .modal-overlay-custom {
            position: fixed;
            top: 0;
            left: 0;
            right: 0;
            bottom: 0;
            background: rgba(0,0,0,0.9);
            backdrop-filter: blur(12px);
            z-index: 1100;
            display: flex;
            align-items: center;
            justify-content: center;
          }
          
          .modal-content-custom {
            background: linear-gradient(135deg, #1e1e3a, #0d0d2b);
            border-radius: 24px;
            padding: 25px;
            max-width: 500px;
            width: 90%;
            max-height: 85vh;
            overflow-y: auto;
            border: 2px solid #a855f7;
            animation: fadeIn 0.3s ease;
          }
          
          .confirm-buttons {
            display: flex;
            gap: 15px;
            justify-content: center;
            margin-top: 20px;
          }
          
          /* Responsive */
          @media (max-width: 768px) {
            .sidebar {
              width: 85%;
              max-width: 320px;
            }
          }
        `}
      </style>
    
      <nav className="navbar-custom w-full flex flex-wrap items-center justify-between px-3 py-3 shadow-lg">
        <div className="container px-4 mx-auto flex flex-wrap items-center justify-between">
          <div className="w-full relative flex justify-between lg:w-auto lg:static lg:block lg:justify-start items-center">
            {/* Settings icon on the left */}
            <div className="settings-icon-btn" onClick={() => setSidebarOpen(true)}>
              <i className="fas fa-cog text-white text-xl"></i>
            </div>
            
            <Link
              to="/"
              className="logo-text text-sm font-bold leading-relaxed inline-block mr-4 py-2 whitespace-nowrap uppercase"
              style={{
                textShadow: "0 0 10px rgba(168, 85, 247, 0.3)",
                letterSpacing: "1px"
              }}
            >
              <i className="fas fa-utensils mr-2"></i>
              Restaurant App
            </Link>
            
            <button
              className="mobile-menu-btn lg:hidden"
              type="button"
              onClick={() => setNavbarOpen(!navbarOpen)}
            >
              <i className="fas fa-bars text-white text-lg"></i>
            </button>
          </div>
          
          <div
            className={
              "lg:flex flex-grow items-center lg:bg-opacity-0 lg:shadow-none transition-all duration-300" +
              (navbarOpen ? " block bg-gradient-to-r from-purple-700 to-purple-900 rounded-2xl mt-3 p-4" : " hidden")
            }
            id="example-navbar-warning"
          >
            <ul className="flex flex-col lg:flex-row list-none lg:ml-auto lg:items-center gap-2 lg:gap-0">
              <li className="flex items-center">
                <Link
                  to="/"
                  className="nav-link text-white px-4 py-2 lg:py-2 flex items-center text-sm uppercase font-semibold transition-all duration-300 rounded-lg hover:bg-white/10"
                >
                  <i className="fas fa-home text-base mr-2"></i>
                  <span>Accueil</span>
                </Link>
              </li>

              <li className="flex items-center">
                <Link
                  to="/restaurants"
                  className="nav-link text-white px-4 py-2 lg:py-2 flex items-center text-sm uppercase font-semibold transition-all duration-300 rounded-lg hover:bg-white/10"
                >
                  <i className="fas fa-utensils text-base mr-2"></i>
                  <span>Restaurants</span>
                </Link>
              </li>

              <li className="flex items-center">
                <Link
                  to="/profile"
                  className="nav-link text-white px-4 py-2 lg:py-2 flex items-center text-sm uppercase font-semibold transition-all duration-300 rounded-lg hover:bg-white/10"
                >
                  <i className="fas fa-user-circle text-base mr-2"></i>
                  <span>Profil</span>
                </Link>
              </li>
            </ul>
          </div>
        </div>
      </nav>
      
      {/* Sidebar */}
      {sidebarOpen && (
        <>
          <div className="sidebar-overlay" onClick={() => setSidebarOpen(false)}></div>
          <div className="sidebar">
            <button 
              onClick={() => setSidebarOpen(false)} 
              style={{ 
                float: 'right', 
                background: 'rgba(255,255,255,0.1)', 
                border: 'none', 
                color: 'white', 
                fontSize: '18px', 
                width: '32px', 
                height: '32px', 
                borderRadius: '8px',
                cursor: 'pointer',
                transition: 'all 0.2s'
              }}
              onMouseEnter={(e) => e.currentTarget.style.background = 'rgba(255,255,255,0.2)'}
              onMouseLeave={(e) => e.currentTarget.style.background = 'rgba(255,255,255,0.1)'}
            >
              ✕
            </button>
            
            <div className="text-center mb-5 mt-2">
              <div style={{ 
                width: '80px', 
                height: '80px', 
                margin: '0 auto', 
                borderRadius: '50%', 
                background: 'linear-gradient(135deg, #6b21a5, #a855f7)',
                padding: '3px'
              }}>
                <img 
                  src={tempProfile.profileImage} 
                  alt="profile" 
                  style={{ width: '100%', height: '100%', borderRadius: '50%', objectFit: 'cover' }}
                />
              </div>
              <h4 className="text-white mt-3 mb-1 font-semibold">{tempProfile.name}</h4>
              <p className="text-purple-200 text-xs">{employeeInfo?.role || "Employé"}</p>
            </div>
            
            <div className="sidebar-section">
              <div className="sidebar-title">
                <i className="fas fa-sliders-h text-sm"></i>
                <span>Paramètres du profil</span>
              </div>
              <label className="sidebar-label">🖼️ Image de couverture</label>
              <input type="text" className="sidebar-input" value={tempProfile.coverImage} onChange={(e) => setTempProfile({...tempProfile, coverImage: e.target.value})} placeholder="URL de l'image" />
              <label className="sidebar-label">👤 Image de profil</label>
              <input type="text" className="sidebar-input" value={tempProfile.profileImage} onChange={(e) => setTempProfile({...tempProfile, profileImage: e.target.value})} placeholder="URL de l'image" />
              <label className="sidebar-label">📛 Nom complet</label>
              <input type="text" className="sidebar-input" value={tempProfile.name} onChange={(e) => setTempProfile({...tempProfile, name: e.target.value})} />
              <label className="sidebar-label">📍 Ville</label>
              <input type="text" className="sidebar-input" value={tempProfile.location} onChange={(e) => setTempProfile({...tempProfile, location: e.target.value})} />
              <label className="sidebar-label">📞 Téléphone</label>
              <input type="tel" className="sidebar-input" value={tempProfile.phone} onChange={(e) => setTempProfile({...tempProfile, phone: e.target.value})} />
              <label className="sidebar-label">📝 Bio</label>
              <textarea className="sidebar-input" rows="2" value={tempProfile.bio} onChange={(e) => setTempProfile({...tempProfile, bio: e.target.value})}></textarea>
              <button className="btn-sidebar" onClick={saveProfileSettings}>
                <i className="fas fa-save mr-2"></i> Enregistrer
              </button>
            </div>
            
            <div className="sidebar-section">
              <div className="sidebar-title">
                <i className="fas fa-share-alt text-sm"></i>
                <span>Liens sociaux</span>
              </div>
              <label className="sidebar-label">📘 Facebook</label>
              <input type="text" className="sidebar-input" placeholder="https://facebook.com/..." value={socialLinks.facebook} onChange={(e) => updateSocialLink('facebook', e.target.value)} />
              <label className="sidebar-label">📷 Instagram</label>
              <input type="text" className="sidebar-input" placeholder="https://instagram.com/..." value={socialLinks.instagram} onChange={(e) => updateSocialLink('instagram', e.target.value)} />
              <label className="sidebar-label">🐦 Twitter</label>
              <input type="text" className="sidebar-input" placeholder="https://twitter.com/..." value={socialLinks.twitter} onChange={(e) => updateSocialLink('twitter', e.target.value)} />
              <label className="sidebar-label">🔗 LinkedIn</label>
              <input type="text" className="sidebar-input" placeholder="https://linkedin.com/..." value={socialLinks.linkedin} onChange={(e) => updateSocialLink('linkedin', e.target.value)} />
              <label className="sidebar-label">🎵 TikTok</label>
              <input type="text" className="sidebar-input" placeholder="https://tiktok.com/..." value={socialLinks.tiktok} onChange={(e) => updateSocialLink('tiktok', e.target.value)} />
              <button className="btn-sidebar" onClick={saveSocialLinks}>
                <i className="fas fa-save mr-2"></i> Enregistrer
              </button>
            </div>
            
            {currentJob && (
              <div className="sidebar-section">
                <div className="sidebar-title">
                  <i className="fas fa-briefcase text-sm"></i>
                  <span>Emploi actuel</span>
                </div>
                <div className="current-job-card">
                  <div style={{ display: 'flex', alignItems: 'center', gap: '12px' }}>
                    <img src={currentJob.logo} alt="logo" style={{ width: '40px', height: '40px', borderRadius: '10px' }} />
                    <div>
                      <h4 style={{ color: '#e9d5ff', margin: 0, fontSize: '0.9rem' }}>{currentJob.restaurantName}</h4>
                      <p style={{ color: 'rgba(255,255,255,0.5)', fontSize: '0.7rem', margin: '3px 0 0' }}>{currentJob.location}</p>
                    </div>
                  </div>
                </div>
                <button className="btn-sidebar btn-danger-sidebar" onClick={() => setShowResignConfirm(true)}>
                  <i className="fas fa-sign-out-alt mr-2"></i> Démissionner
                </button>
              </div>
            )}
            
            {!currentJob && (
              <div className="sidebar-section">
                <div className="sidebar-title">
                  <i className="fas fa-bell text-sm"></i>
                  <span>Offres d'emploi reçues</span>
                  {jobOffers.filter(j => j.status === "pending").length > 0 && (
                    <span className="bg-red-500 text-white text-xs rounded-full px-2 py-0.5 ml-2">
                      {jobOffers.filter(j => j.status === "pending").length}
                    </span>
                  )}
                </div>
                {jobOffers.filter(j => j.status === "pending").length === 0 ? (
                  <p className="text-gray-300 text-sm text-center py-3">Aucune offre pour le moment</p>
                ) : (
                  jobOffers.filter(j => j.status === "pending").map(offer => (
                    <div key={offer.id} className="job-offer-card" onClick={() => { setSelectedJobOffer(offer); setShowJobOfferModal(true); }}>
                      <div style={{ display: 'flex', alignItems: 'center', gap: '10px' }}>
                        <img src={offer.logo} alt="logo" style={{ width: '35px', height: '35px', borderRadius: '8px' }} />
                        <div>
                          <h4 style={{ color: 'white', margin: 0, fontSize: '0.85rem' }}>{offer.restaurantName}</h4>
                          <p style={{ color: 'rgba(255,255,255,0.5)', fontSize: '0.65rem', margin: '2px 0 0' }}>{offer.location}</p>
                        </div>
                      </div>
                    </div>
                  ))
                )}
              </div>
            )}
            
            <div className="sidebar-section">
              <button className="btn-sidebar btn-danger-sidebar" onClick={() => setShowLogoutConfirm(true)}>
                <i className="fas fa-power-off mr-2"></i> Déconnexion
              </button>
            </div>
          </div>
        </>
      )}
      
      {/* Modal offre d'emploi */}
      {showJobOfferModal && selectedJobOffer && (
        <div className="modal-overlay-custom" onClick={() => setShowJobOfferModal(false)}>
          <div className="modal-content-custom" onClick={(e) => e.stopPropagation()}>
            <button onClick={() => setShowJobOfferModal(false)} style={{ float: 'right', background: 'rgba(255,255,255,0.1)', border: 'none', color: 'white', fontSize: '18px', width: '30px', height: '30px', borderRadius: '8px', cursor: 'pointer' }}>✕</button>
            <div className="text-center">
              <img src={selectedJobOffer.logo} alt="logo" style={{ width: '70px', height: '70px', borderRadius: '50%', marginBottom: '10px' }} />
              <h3 style={{ color: '#a855f7', marginBottom: '5px' }}>{selectedJobOffer.restaurantName}</h3>
              <p style={{ color: 'rgba(255,255,255,0.7)' }}>📍 {selectedJobOffer.location}</p>
            </div>
            <img src={selectedJobOffer.image} alt="restaurant" style={{ width: '100%', height: '150px', objectFit: 'cover', borderRadius: '15px', margin: '15px 0' }} />
            <p style={{ color: 'rgba(255,255,255,0.8)', marginBottom: '15px' }}>{selectedJobOffer.description}</p>
            <div style={{ marginBottom: '15px' }}>
              <p style={{ color: 'rgba(255,255,255,0.6)', fontSize: '0.8rem' }}>📞 {selectedJobOffer.phone}</p>
              <p style={{ color: 'rgba(255,255,255,0.6)', fontSize: '0.8rem' }}>✉️ {selectedJobOffer.email}</p>
            </div>
            <div className="confirm-buttons">
              <button className="btn-sidebar" style={{ background: '#22c55e' }} onClick={() => acceptJobOffer(selectedJobOffer)}>
                <i className="fas fa-check mr-2"></i> Accepter
              </button>
              <button className="btn-sidebar btn-danger-sidebar" onClick={() => rejectJobOffer(selectedJobOffer)}>
                <i className="fas fa-times mr-2"></i> Refuser
              </button>
            </div>
          </div>
        </div>
      )}
      
      {/* Modal démission */}
      {showResignConfirm && (
        <div className="modal-overlay-custom" onClick={() => setShowResignConfirm(false)}>
          <div className="modal-content-custom" style={{ maxWidth: '350px', textAlign: 'center' }} onClick={(e) => e.stopPropagation()}>
            <div style={{ fontSize: '3rem', marginBottom: '10px' }}>⚠️</div>
            <h3 style={{ color: 'white', marginBottom: '15px' }}>Démission</h3>
            <p style={{ color: 'rgba(255,255,255,0.8)', marginBottom: '20px' }}>Êtes-vous sûr de vouloir démissionner ?</p>
            <div className="confirm-buttons">
              <button className="btn-sidebar" style={{ background: '#22c55e' }} onClick={resignFromJob}>Oui</button>
              <button className="btn-sidebar btn-danger-sidebar" onClick={() => setShowResignConfirm(false)}>Non</button>
            </div>
          </div>
        </div>
      )}
      
      {/* Modal déconnexion */}
      {showLogoutConfirm && (
        <div className="modal-overlay-custom" onClick={() => setShowLogoutConfirm(false)}>
          <div className="modal-content-custom" style={{ maxWidth: '350px', textAlign: 'center' }} onClick={(e) => e.stopPropagation()}>
            <div style={{ fontSize: '3rem', marginBottom: '10px' }}>🚪</div>
            <h3 style={{ color: 'white', marginBottom: '15px' }}>Déconnexion</h3>
            <p style={{ color: 'rgba(255,255,255,0.8)', marginBottom: '20px' }}>Êtes-vous sûr de vouloir vous déconnecter ?</p>
            <div className="confirm-buttons">
              <button className="btn-sidebar" style={{ background: '#22c55e' }} onClick={handleLogout}>Oui</button>
              <button className="btn-sidebar btn-danger-sidebar" onClick={() => setShowLogoutConfirm(false)}>Non</button>
            </div>
          </div>
        </div>
      )}
      
      {/* Icônes sociales */}
      <div style={{ position: 'fixed', bottom: '20px', left: 0, right: 0, zIndex: 50 }}>
        <SocialIcons />
      </div>
    </>
  );
}
